const BOT_TOKEN='8794560347:AAFLk7ZT6ktdnUex2RvZHYaXZuNhJ8eVVqY';
const TG=`https://api.telegram.org/bot${BOT_TOKEN}`;
const ADMIN_ID='5307233657';
const GROQ_KEY='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';

const usuarios=$('👥 GS: Usuarios').all().map(i=>i.json).filter(i=>i.telegram_id);
const sesiones=$('🔄 GS: Sesiones').all().map(i=>i.json).filter(i=>i.telegram_id);
const stock=$('📦 GS: Stock').all().map(i=>i.json).filter(i=>i.id_producto);
const movPendientes=$('📋 GS: Movimientos').all().map(i=>i.json).filter(i=>i.id_movimiento&&i.estado==='pendiente');
const facturasPend=$('📄 GS: Facturas').all().map(i=>i.json).filter(i=>i.id_factura&&i.factura_realizada==='NO');
// Webhook recibe un update a la vez directamente de Telegram
const updates=[$('📲 Webhook Telegram').first().json.body];

async function tgSend(chatId,text,kb){
  const b={chat_id:String(chatId),text,parse_mode:'HTML'};
  if(kb)b.reply_markup={inline_keyboard:kb};
  try{await this.helpers.httpRequest({method:'POST',url:`${TG}/sendMessage`,body:b,json:true});}catch(e){}
}
async function tgAnswer(id){
  try{await this.helpers.httpRequest({method:'POST',url:`${TG}/answerCallbackQuery`,body:{callback_query_id:id,text:''},json:true});}catch(e){}
}

const findUser=(uid)=>usuarios.find(u=>String(u.telegram_id)===String(uid))||null;
const findSesion=(uid)=>sesiones.find(s=>String(s.telegram_id)===String(uid))||null;
const findProd=(q)=>{const ql=(q||'').toLowerCase().trim();return stock.filter(p=>(p.id_producto||'').toLowerCase().includes(ql)||(p.marca||'').toLowerCase().includes(ql)||(p.modelo||'').toLowerCase().includes(ql)||(p.descripcion||'').toLowerCase().includes(ql));};

function mainMenu(rol){
  const kb=[[{text:'📦 Consultar Stock',callback_data:'stock'}]];
  if(['operador','aprobador','administrador'].includes(rol))kb.push([{text:'📋 Registrar Movimiento',callback_data:'movimiento'}]);
  if(['aprobador','administrador'].includes(rol)){const n=movPendientes.length+facturasPend.length;kb.push([{text:`✅ Pendientes${n>0?' ('+n+')':''}`,callback_data:'pendientes'}]);}
  if(rol==='administrador')kb.push([{text:'⚙️ Panel Admin',callback_data:'admin'}]);
  return kb;
}

const gsWrites=[];
const now=()=>new Date().toLocaleString('es-AR',{timeZone:'America/Argentina/Buenos_Aires',year:'numeric',month:'2-digit',day:'2-digit',hour:'2-digit',minute:'2-digit',second:'2-digit',hour12:false}).split('/').join('-').replace(', ',' ');
let lastUpdateId=-1;

for(const update of updates){
  lastUpdateId=update.update_id;
  let userId,chatId,text,cb,cbId,firstName,message;
  if(update.callback_query){const q=update.callback_query;userId=String(q.from.id);chatId=String(q.message.chat.id);firstName=q.from.first_name||'';cb=q.data||'';cbId=q.id;text='';message=null;}
  else if(update.message){const m=update.message;userId=String(m.from.id);chatId=String(m.chat.id);firstName=m.from.first_name||'';text=m.text||'';cb='';cbId=null;message=m;}
  else{continue;}
  if(cbId)await tgAnswer.call(this,cbId);

  // Transcribir nota de voz con Groq Whisper
  if(message?.voice&&!text){
    const vfid=message.voice.file_id;
    try{
      await tgSend.call(this,chatId,'🎤 Transcribiendo...');
      const fi=await this.helpers.httpRequest({method:'GET',url:`${TG}/getFile?file_id=${vfid}`,json:true});
      const fp=fi?.result?.file_path;
      if(!fp){await tgSend.call(this,chatId,'❌ No pude obtener el audio.');continue;}
      const audioData=await this.helpers.httpRequest({method:'GET',url:`https://api.telegram.org/file/bot${BOT_TOKEN}/${fp}`,encoding:null,json:false});
      const tr=await this.helpers.httpRequest({method:'POST',url:'https://api.groq.com/openai/v1/audio/transcriptions',headers:{Authorization:`Bearer ${GROQ_KEY}`},formData:{file:{value:Buffer.from(audioData),options:{filename:'voice.ogg',contentType:'audio/ogg'}},model:'whisper-large-v3-turbo',language:'es'},json:true});
      text=tr?.text||'';
      if(!text){await tgSend.call(this,chatId,'❌ No entendí el audio. Intentá escribir el mensaje.');continue;}
      await tgSend.call(this,chatId,`🎤 Entendí: <i>"${text}"</i>`);
    }catch(e){
      await tgSend.call(this,chatId,'❌ Error al transcribir: '+e.message);
      continue;
    }
  }

  let user=findUser(userId);
  if(!user&&userId===ADMIN_ID){
    user={telegram_id:userId,nombre:firstName,rol:'administrador',activo:'TRUE',fecha_alta:now()};
    gsWrites.push({_sheet:'USUARIOS',_op:'append',...user});
  }
  if(!user){await tgSend.call(this,chatId,'No estás registrado. Contactá al administrador.');continue;}
  if(user.activo==='FALSE'){await tgSend.call(this,chatId,'Tu cuenta está inactiva.');continue;}
  const rol=user.rol||'operador';

  const sesion=findSesion(userId);
  const estado=sesion?.estado||'';
  let datos={};try{datos=sesion?.datos?JSON.parse(sesion.datos):{};}catch(e){}
  const saveSession=(est,dat)=>gsWrites.push({_sheet:'SESIONES',_op:'upsert',telegram_id:userId,estado:est,datos:JSON.stringify(dat||{}),ts:now()});
  const clearSession=()=>saveSession('',{});

  // /start
  if(text==='/start'||cb==='main_menu'){
    clearSession();
    await tgSend.call(this,chatId,`Hola <b>${user.nombre}</b> (${rol}) 👋\n¿Qué querés hacer?`,mainMenu(rol));
    continue;
  }

  // Consultar Stock
  if(cb==='stock'){saveSession('WAIT_SEARCH',{});await tgSend.call(this,chatId,'🔍 <b>Consultar Stock</b>\nEscribí el nombre del producto:',[[{text:'❌ Cancelar',callback_data:'main_menu'}]]);continue;}
  if(estado==='WAIT_SEARCH'&&text){
    const res=findProd(text);clearSession();
    if(!res.length){await tgSend.call(this,chatId,`No encontré "${text}" en el stock.`,[[{text:'🔍 Buscar de nuevo',callback_data:'stock'},{text:'🏠 Menú',callback_data:'main_menu'}]]);}
    else{let msg=`📦 <b>Resultados para "${text}":</b>\n\n`;for(const p of res){const stk=p.tipo==='accesorio'?`Stock: ${p.stock_actual}`:`Estado: ${p.estado_unidad||'disponible'}`;msg+=`<b>${p.marca} ${p.modelo}</b> (${p.id_producto})\n${p.descripcion||''} | ${p.ubicacion||'local'}\n${stk}\n💰 Máx: ${p.precio_max||'-'} | Mín: ${p.precio_min||'-'}\n\n`;}await tgSend.call(this,chatId,msg.trim(),[[{text:'🔍 Nueva búsqueda',callback_data:'stock'},{text:'🏠 Menú',callback_data:'main_menu'}]]);}
    continue;
  }

  // Registrar Movimiento
  if(cb==='movimiento'){
    if(!['operador','aprobador','administrador'].includes(rol)){await tgSend.call(this,chatId,'Sin permiso.');continue;}
    saveSession('MOV_INICIO',{});
    await tgSend.call(this,chatId,'📋 ¿Es producto nuevo o ya existe en stock?',[[{text:'🆕 Producto nuevo',callback_data:'mov_nuevo'},{text:'📦 Ya existe',callback_data:'mov_exist'}],[{text:'❌ Cancelar',callback_data:'main_menu'}]]);continue;
  }

  // Flujo NUEVO producto
  if(cb==='mov_nuevo'&&estado==='MOV_INICIO'){
    saveSession('MOV_NUEVO',{});
    await tgSend.call(this,chatId,'📦 <b>Nuevo producto + entrada de stock</b>\nMandame todo en un mensaje:\n\n<code>tipo, marca, modelo, descripcion, precio, stock_minimo, rodado, cantidad, referencia</code>\n\nEl código se genera automático (B01, C01, A01...)\n\n<i>Ejemplo bici:</i>\n<code>bicicleta, Giant, Talon 29, MTB aluminio, 280000, 1, 29, 2, Compra proveedor ABC</code>\n\n<i>Ejemplo accesorio (rodado vacío):</i>\n<code>accesorio, Shimano, Cadena XT, Cadena 11v, 8000, 5, , 10, Proveedor XYZ</code>',[[{text:'❌ Cancelar',callback_data:'main_menu'}]]);continue;
  }
  if(estado==='MOV_NUEVO'&&text){
    const p=text.split(',').map(x=>x.trim());
    if(p.length<7){await tgSend.call(this,chatId,'Faltan datos. Necesito al menos 9 campos separados por coma.');continue;}
    const[tipo,marca,modelo,desc,precio,stMin,rodado,cantidad,...refParts]=p;
    const referencia=refParts.join(',').trim()||'Sin referencia';
    const cant=parseInt(cantidad);
    if(isNaN(cant)||cant<=0){await tgSend.call(this,chatId,'La cantidad debe ser un número mayor a 0.');continue;}
    // Auto-generar ID
    const prefix=tipo.toLowerCase()==='bicicleta'?'B':tipo.toLowerCase()==='cuadro'?'C':tipo.toLowerCase()==='accesorio'?'A':'P';
    const existentes=stock.filter(s=>(s.id_producto||'').toUpperCase().startsWith(prefix)).map(s=>parseInt((s.id_producto||'').slice(prefix.length))).filter(n=>!isNaN(n));
    const siguiente=existentes.length?Math.max(...existentes)+1:1;
    const id=prefix+String(siguiente).padStart(2,'0');
    saveSession('MOV_NUEVO_CONF',{id,tipo,marca,modelo,desc,precio:precio||'0',stMin:stMin||'1',rodado:rodado||'',cantidad:cant,referencia});
    await tgSend.call(this,chatId,`📦 <b>Confirmar:</b>\nCódigo asignado: <b>${id}</b>\nTipo: ${tipo} | ${marca} ${modelo}${rodado?'\nRodado: '+rodado:''}\nDescripción: ${desc}\nPrecio: $${precio||'0'} | Stock mín: ${stMin||'1'}\n\n📥 Entrada: ${cant} unidades\nRef: ${referencia}`,[[{text:'✅ Confirmar',callback_data:'movnew_ok'},{text:'❌ Cancelar',callback_data:'main_menu'}]]);continue;
  }
  if(cb==='movnew_ok'&&estado==='MOV_NUEVO_CONF'){
    const d=datos;const t=now();const movId=`MOV-${Date.now()}`;
    gsWrites.push({_sheet:'STOCK',_op:'append',id_producto:d.id,tipo:d.tipo,marca:d.marca,modelo:d.modelo,numero_serie:'',descripcion:d.desc,ubicacion:'local',stock_actual:'0',stock_minimo:d.stMin,estado_unidad:'disponible',precio_costo:'0',precio_venta:d.precio,rodado:d.rodado,fecha_ingreso:t,ultima_actualizacion:t});
    gsWrites.push({_sheet:'MOVIMIENTOS_PENDIENTES',_op:'append',id_movimiento:movId,tipo:'entrada',estado:'pendiente',id_producto:d.id,numero_serie:'',cantidad:d.cantidad,descripcion_movimiento:`entrada ${d.cantidad}u ${d.id}`,referencia_doc:d.referencia,hash_duplicado:`${d.id}-entrada-${d.cantidad}-${d.referencia}`,telegram_id_operador:userId,nombre_operador:user.nombre,telegram_id_aprobador:'',nombre_aprobador:'',fecha_creacion:t,fecha_aprobacion:'',motivo_rechazo:'',notas_aprobador:''});
    clearSession();
    await tgSend.call(this,chatId,`✅ Producto <b>${d.id}</b> creado y movimiento <b>${movId}</b> enviado para aprobación.`,[[{text:'🏠 Menú',callback_data:'main_menu'}]]);
    for(const u of usuarios){if(['aprobador','administrador'].includes(u.rol)&&String(u.telegram_id)!==userId&&u.activo==='TRUE'){await tgSend.call(this,u.telegram_id,`⚠️ Nuevo producto + entrada de ${user.nombre}:\nProducto: ${d.id} ${d.marca} ${d.modelo}\nCantidad: ${d.cantidad}\nRef: ${d.referencia}`,[[{text:'✅ Ver pendientes',callback_data:'pendientes'}]]);}}
    continue;
  }

  // Flujo producto EXISTENTE
  if(cb==='mov_exist'&&estado==='MOV_INICIO'){saveSession('MOV_TIPO',{});await tgSend.call(this,chatId,'📋 Tipo de movimiento:',[[{text:'📥 Entrada',callback_data:'mov_e'},{text:'📤 Salida',callback_data:'mov_s'}],[{text:'🔄 Transferencia',callback_data:'mov_transf'}],[{text:'❌ Cancelar',callback_data:'main_menu'}]]);continue;}
  if(cb==='mov_transf'&&estado==='MOV_TIPO'){saveSession('MOV_TRANSF_PROD',{});await tgSend.call(this,chatId,'🔄 <b>Transferencia</b>\nID del producto a transferir:',[[{text:'❌ Cancelar',callback_data:'main_menu'}]]);continue;}
  if(estado==='MOV_TRANSF_PROD'&&text){
    const p=stock.find(p=>(p.id_producto||'').toUpperCase()===text.trim().toUpperCase());
    if(!p){await tgSend.call(this,chatId,`Producto "${text}" no encontrado.`);continue;}
    saveSession('MOV_TRANSF_DEST',{id_producto:p.id_producto,marca:p.marca,modelo:p.modelo,ubic_actual:p.ubicacion||'sin ubicación'});
    await tgSend.call(this,chatId,`Producto: <b>${p.marca} ${p.modelo}</b>\nUbicación actual: ${p.ubicacion||'sin ubicación'}\n\n¿A dónde lo transferís?`,[[{text:'🏪 Local',callback_data:'transf_local'},{text:'🏭 Galpón',callback_data:'transf_galpon'}],[{text:'❌ Cancelar',callback_data:'main_menu'}]]);continue;
  }
  if((cb==='transf_local'||cb==='transf_galpon')&&estado==='MOV_TRANSF_DEST'){
    const destino=cb==='transf_local'?'local':'galpon';
    const d=datos;
    saveSession('MOV_TRANSF_CONF',{...d,destino});
    await tgSend.call(this,chatId,`🔄 <b>Confirmar transferencia:</b>\nProducto: ${d.id_producto} - ${d.marca} ${d.modelo}\nDe: ${d.ubic_actual} → A: ${destino}`,[[{text:'✅ Confirmar',callback_data:'transf_ok'},{text:'❌ Cancelar',callback_data:'main_menu'}]]);continue;
  }
  if(cb==='transf_ok'&&estado==='MOV_TRANSF_CONF'){
    const d=datos;
    gsWrites.push({_sheet:'STOCK',_op:'update',id_producto:d.id_producto,ubicacion:d.destino,ultima_actualizacion:now()});
    clearSession();
    await tgSend.call(this,chatId,`✅ <b>${d.marca} ${d.modelo}</b> transferido a <b>${d.destino}</b>.`,[[{text:'🏠 Menú',callback_data:'main_menu'}]]);continue;
  }
  if((cb==='mov_e'||cb==='mov_s')&&estado==='MOV_TIPO'){saveSession('MOV_PROD',{tipo:cb==='mov_e'?'entrada':'salida'});await tgSend.call(this,chatId,'ID del producto:',[[{text:'❌ Cancelar',callback_data:'main_menu'}]]);continue;}
  if(estado==='MOV_PROD'&&text){
    const p=stock.find(p=>(p.id_producto||'').toUpperCase()===text.trim().toUpperCase());
    if(!p){await tgSend.call(this,chatId,`Producto "${text}" no encontrado.`);continue;}
    saveSession('MOV_CANT',{...datos,id_producto:p.id_producto,marca:p.marca,modelo:p.modelo});
    await tgSend.call(this,chatId,`Producto: <b>${p.marca} ${p.modelo}</b>\nCantidad:`,[[{text:'❌ Cancelar',callback_data:'main_menu'}]]);continue;
  }
  if(estado==='MOV_CANT'&&text){const cant=parseInt(text);if(isNaN(cant)||cant<=0){await tgSend.call(this,chatId,'Ingresá un número válido:');continue;}saveSession('MOV_REF',{...datos,cantidad:cant});await tgSend.call(this,chatId,'Referencia/documento:',[[{text:'❌ Cancelar',callback_data:'main_menu'}]]);continue;}
  if(estado==='MOV_REF'&&text){const d={...datos,referencia:text};saveSession('MOV_CONF',d);await tgSend.call(this,chatId,`📋 <b>Confirmar:</b>\nTipo: ${d.tipo}\nProducto: ${d.id_producto} - ${d.marca} ${d.modelo}\nCantidad: ${d.cantidad}\nRef: ${d.referencia}`,[[{text:'✅ Confirmar',callback_data:'mov_ok'},{text:'❌ Cancelar',callback_data:'main_menu'}]]);continue;}
  if(cb==='mov_ok'&&estado==='MOV_CONF'){
    const d=datos;const movId=`MOV-${Date.now()}`;
    gsWrites.push({_sheet:'MOVIMIENTOS_PENDIENTES',_op:'append',id_movimiento:movId,tipo:d.tipo,estado:'pendiente',id_producto:d.id_producto,numero_serie:'',cantidad:d.cantidad,descripcion_movimiento:`${d.tipo} ${d.cantidad}u ${d.id_producto}`,referencia_doc:d.referencia,hash_duplicado:`${d.id_producto}-${d.tipo}-${d.cantidad}-${d.referencia}`,telegram_id_operador:userId,nombre_operador:user.nombre,telegram_id_aprobador:'',nombre_aprobador:'',fecha_creacion:now(),fecha_aprobacion:'',motivo_rechazo:'',notas_aprobador:''});
    clearSession();
    await tgSend.call(this,chatId,`✅ Movimiento <b>${movId}</b> enviado para aprobación.`,[[{text:'🏠 Menú',callback_data:'main_menu'}]]);
    for(const u of usuarios){if(['aprobador','administrador'].includes(u.rol)&&String(u.telegram_id)!==userId&&u.activo==='TRUE'){await tgSend.call(this,u.telegram_id,`⚠️ Nuevo movimiento de ${user.nombre}:\n${d.tipo} ${d.cantidad}x ${d.id_producto}\nRef: ${d.referencia}`,[[{text:'✅ Ver pendientes',callback_data:'pendientes'}]]);}}
    continue;
  }

  // Pendientes
  if(cb==='pendientes'){
    if(!['aprobador','administrador'].includes(rol)){await tgSend.call(this,chatId,'Sin permiso.');continue;}
    if(!movPendientes.length&&!facturasPend.length){await tgSend.call(this,chatId,'✅ No hay pendientes.',[[{text:'🏠 Menú',callback_data:'main_menu'}]]);clearSession();continue;}
    for(const mov of movPendientes.slice(0,5)){
      await tgSend.call(this,chatId,`📋 <b>Movimiento pendiente</b>\n\nID: ${mov.id_movimiento}\nTipo: ${mov.tipo}\nProducto: ${mov.id_producto}\nCantidad: ${mov.cantidad}\nRef: ${mov.referencia_doc}\nOperador: ${mov.nombre_operador}`,[[{text:'✅ Aprobar',callback_data:`apr_${mov.id_movimiento}`},{text:'❌ Rechazar',callback_data:`rej_${mov.id_movimiento}`}]]);
    }
    for(const f of facturasPend.slice(0,5)){
      await tgSend.call(this,chatId,`🧾 <b>Factura pendiente</b>\n\nCliente: ${f.nombre}\nDomicilio: ${f.domicilio}\nDNI/CUIT: ${f.dni_cuit}\nTipo: ${f.tipo}\nDescripción: ${f.descripcion_producto}\nPrecio: $${f.precio_venta}\nFecha: ${f.fecha?.substring(0,10)||''}`,[[{text:'✅ Datos OK',callback_data:`factok_${f.id_factura}`}]]);
    }
    const extra=(movPendientes.length>5?movPendientes.length-5:0)+(facturasPend.length>5?facturasPend.length-5:0);
    if(extra>0)await tgSend.call(this,chatId,`... y ${extra} más en la planilla.`);
    continue;
  }

  // Aprobar
  if(cb.startsWith('apr_')){
    if(!['aprobador','administrador'].includes(rol)){await tgSend.call(this,chatId,'Sin permiso.');continue;}
    const movId=cb.slice(4);
    const allMovs=$('📋 GS: Movimientos').all().map(i=>i.json).filter(i=>i.id_movimiento);
    const mov=allMovs.find(m=>m.id_movimiento===movId);
    if(!mov){await tgSend.call(this,chatId,'Movimiento no encontrado.');clearSession();continue;}
    const fechaApr=now();
    gsWrites.push({_sheet:'MOVIMIENTOS_PENDIENTES',_op:'update',id_movimiento:movId,estado:'aprobado',telegram_id_aprobador:userId,nombre_aprobador:user.nombre,fecha_aprobacion:fechaApr,motivo_rechazo:'',notas_aprobador:''});
    gsWrites.push({_sheet:'HISTORIAL',_op:'append',id_movimiento:movId,tipo:mov.tipo,estado:'aprobado',id_producto:mov.id_producto,cantidad:mov.cantidad,referencia_doc:mov.referencia_doc,telegram_id_operador:mov.telegram_id_operador,nombre_operador:mov.nombre_operador,telegram_id_aprobador:userId,nombre_aprobador:user.nombre,fecha_creacion:mov.fecha_creacion,fecha_aprobacion:fechaApr,motivo_rechazo:'',notas_aprobador:''});
    // Actualizar stock
    const prod=stock.find(p=>p.id_producto===mov.id_producto);
    if(prod){
      let nuevoStock=parseInt(prod.stock_actual||0);
      if(mov.tipo==='entrada')nuevoStock+=parseInt(mov.cantidad||0);
      else if(mov.tipo==='salida')nuevoStock-=parseInt(mov.cantidad||0);
      if(nuevoStock<0)nuevoStock=0;
      gsWrites.push({_sheet:'STOCK',_op:'update',id_producto:mov.id_producto,stock_actual:String(nuevoStock),ultima_actualizacion:fechaApr});
    }
    clearSession();
    await tgSend.call(this,chatId,`✅ Movimiento <b>${movId}</b> aprobado.\nStock actualizado.`,[[{text:'📋 Ver más',callback_data:'pendientes'},{text:'🏠 Menú',callback_data:'main_menu'}]]);
    if(mov.telegram_id_operador)await tgSend.call(this,mov.telegram_id_operador,`✅ Tu movimiento <b>${movId}</b> fue aprobado por ${user.nombre}.`);
    continue;
  }

  // Rechazar (paso 1: pedir motivo)
  if(cb.startsWith('rej_')){
    if(!['aprobador','administrador'].includes(rol)){await tgSend.call(this,chatId,'Sin permiso.');continue;}
    const movId=cb.slice(4);
    saveSession('WAIT_REJ',{movId});
    await tgSend.call(this,chatId,'Motivo del rechazo:',[[{text:'❌ Cancelar',callback_data:'main_menu'}]]);
    continue;
  }

  // Rechazar (paso 2: guardar motivo)
  if(estado==='WAIT_REJ'&&text){
    const movId=datos.movId;
    const allMovs=$('📋 GS: Movimientos').all().map(i=>i.json).filter(i=>i.id_movimiento);
    const mov=allMovs.find(m=>m.id_movimiento===movId);
    const fechaRej=now();
    gsWrites.push({_sheet:'MOVIMIENTOS_PENDIENTES',_op:'update',id_movimiento:movId,estado:'rechazado',telegram_id_aprobador:userId,nombre_aprobador:user.nombre,fecha_aprobacion:fechaRej,motivo_rechazo:text,notas_aprobador:''});
    gsWrites.push({_sheet:'HISTORIAL',_op:'append',id_movimiento:movId,tipo:mov?.tipo||'',estado:'rechazado',id_producto:mov?.id_producto||'',cantidad:mov?.cantidad||'',referencia_doc:mov?.referencia_doc||'',telegram_id_operador:mov?.telegram_id_operador||'',nombre_operador:mov?.nombre_operador||'',telegram_id_aprobador:userId,nombre_aprobador:user.nombre,fecha_creacion:mov?.fecha_creacion||'',fecha_aprobacion:fechaRej,motivo_rechazo:text,notas_aprobador:''});
    clearSession();
    await tgSend.call(this,chatId,`❌ Movimiento <b>${movId}</b> rechazado.`,[[{text:'📋 Ver más',callback_data:'pendientes'},{text:'🏠 Menú',callback_data:'main_menu'}]]);
    if(mov?.telegram_id_operador)await tgSend.call(this,mov.telegram_id_operador,`❌ Tu movimiento <b>${movId}</b> fue rechazado por ${user.nombre}.\nMotivo: ${text}`);
    continue;
  }

  // Factura
  // Facturas pendientes
  if(cb==='fact_pend'){
    if(!['aprobador','administrador'].includes(rol)){await tgSend.call(this,chatId,'Sin permiso.');continue;}
    if(!facturasPend.length){await tgSend.call(this,chatId,'✅ No hay facturas pendientes.',[[{text:'🏠 Menú',callback_data:'main_menu'}]]);clearSession();continue;}
    for(const f of facturasPend.slice(0,5)){
      await tgSend.call(this,chatId,`🧾 <b>Factura pendiente</b>\n\nCliente: ${f.nombre}\nDomicilio: ${f.domicilio}\nDNI/CUIT: ${f.dni_cuit}\nTipo: ${f.tipo}\nDescripción: ${f.descripcion_producto}\nPrecio: $${f.precio_venta}\nFecha: ${f.fecha?.substring(0,10)||''}`,[[{text:'✅ Datos OK',callback_data:`factok_${f.id_factura}`}]]);
    }
    if(facturasPend.length>5)await tgSend.call(this,chatId,`... y ${facturasPend.length-5} más en la planilla.`);
    continue;
  }
  if(cb.startsWith('factok_')){
    if(!['aprobador','administrador'].includes(rol)){await tgSend.call(this,chatId,'Sin permiso.');continue;}
    const facId=cb.slice(7);
    gsWrites.push({_sheet:'FACTURAS',_op:'update',id_factura:facId,factura_realizada:'SI'});
    clearSession();
    await tgSend.call(this,chatId,`✅ Factura <b>${facId}</b> marcada como realizada.`,[[{text:'🧾 Ver más',callback_data:'fact_pend'},{text:'🏠 Menú',callback_data:'main_menu'}]]);continue;
  }

  // Factura
  if(cb==='factura'){
    saveSession('FACT_DATA',{});
    await tgSend.call(this,chatId,'🧾 <b>Datos para factura</b>\nMandame todo en un mensaje con este formato:\n\n<code>Nombre, Domicilio, DNI/CUIT, Tipo (A o B), Descripción, Precio</code>\n\n<i>Ejemplo:</i>\n<code>Juan García, Av. Corrientes 123, 20-12345678-9, B, Trek Mountain Pro 29, 150000</code>',[[{text:'❌ Cancelar',callback_data:'main_menu'}]]);continue;
  }
  if(estado==='FACT_DATA'&&text){
    const p=text.split(',').map(x=>x.trim());
    if(p.length<6){await tgSend.call(this,chatId,'Faltan datos. Mandá los 6 campos separados por coma:\n<code>Nombre, Domicilio, DNI/CUIT, Tipo, Descripción, Precio</code>');continue;}
    const[nombre,domicilio,dni_cuit,tipo,descripcion,precioRaw]=p;
    const precio=(precioRaw||'0').trim().replace(/./g,'').replace(',','.');
    const tipoUpper=(tipo||'').toUpperCase();
    if(!['A','B'].includes(tipoUpper)){await tgSend.call(this,chatId,'El tipo debe ser A o B. Reintentá.');continue;}
    saveSession('FACT_CONF',{nombre,domicilio,dni_cuit,tipo:tipoUpper,descripcion,precio});
    await tgSend.call(this,chatId,`🧾 <b>Confirmar datos:</b>\nCliente: ${nombre}\nDomicilio: ${domicilio}\nDNI/CUIT: ${dni_cuit}\nTipo: ${tipoUpper}\nDescripción: ${descripcion}\nPrecio: $${precio}`,[[{text:'✅ Confirmar',callback_data:'fact_ok'},{text:'❌ Cancelar',callback_data:'main_menu'}]]);continue;
  }
  if(cb==='fact_ok'&&estado==='FACT_CONF'){
    const d=datos;
    gsWrites.push({_sheet:'FACTURAS',_op:'append',id_factura:`FAC-${Date.now()}`,nombre:d.nombre,domicilio:d.domicilio,dni_cuit:d.dni_cuit,tipo:d.tipo,descripcion_producto:d.descripcion,precio_venta:d.precio,fecha:now(),factura_realizada:'NO'});
    clearSession();
    await tgSend.call(this,chatId,'✅ Datos de factura guardados. Revisá la hoja FACTURAS en Google Sheets.',[[{text:'🏠 Menú',callback_data:'main_menu'}]]);continue;
  }

  // Admin panel
  if(cb==='admin'&&rol==='administrador'){await tgSend.call(this,chatId,'⚙️ <b>Panel Admin:</b>',[[{text:'👤 Agregar Usuario',callback_data:'adm_user'}],[{text:'🧾 Cargar Datos Factura',callback_data:'factura'}],[{text:'📷 Carga por Factura (OCR)',callback_data:'fact_prov'}],[{text:'🏠 Menú',callback_data:'main_menu'}]]);continue;}
  if(cb==='adm_user'&&rol==='administrador'){saveSession('ADM_USER',{});await tgSend.call(this,chatId,'Datos del usuario:\n<code>ID_telegram,nombre,rol</code>\nRoles: operador / aprobador / administrador',[[{text:'❌ Cancelar',callback_data:'main_menu'}]]);continue;}
  if(estado==='ADM_USER'&&text){
    const parts=text.split(',').map(p=>p.trim());if(parts.length<3){await tgSend.call(this,chatId,'Formato: ID,nombre,rol');continue;}
    const[nId,nNombre,nRol]=parts;if(findUser(nId)){await tgSend.call(this,chatId,`Ya existe ID ${nId}.`);clearSession();continue;}
    gsWrites.push({_sheet:'USUARIOS',_op:'append',telegram_id:nId,nombre:nNombre,rol:nRol,activo:'TRUE',fecha_alta:now()});
    clearSession();await tgSend.call(this,chatId,`✅ Usuario ${nNombre} (${nRol}) agregado.`,[[{text:'⚙️ Admin',callback_data:'admin'}]]);continue;
  }

  // OCR: Carga de stock por factura de proveedor
  if(cb==='fact_prov'&&rol==='administrador'){saveSession('FACT_PROV_WAIT',{});await tgSend.call(this,chatId,'📷 <b>Carga por factura de proveedor</b>\nMandame una foto o PDF de la factura. Gemini detectará los productos automáticamente.',[[{text:'❌ Cancelar',callback_data:'main_menu'}]]);continue;}
  if(estado==='FACT_PROV_WAIT'&&message&&(message.photo||message.document)){
    if(!GROQ_KEY){await tgSend.call(this,chatId,'❌ No hay API key de Groq configurada.');clearSession();continue;}
    const isPhoto=!!message.photo;
    const fileId=isPhoto?message.photo[message.photo.length-1].file_id:message.document.file_id;
    const mimeType=isPhoto?'image/jpeg':(message.document?.mime_type||'image/jpeg');
    await tgSend.call(this,chatId,'🔍 Analizando con IA...');
    const fileInfo=await this.helpers.httpRequest({method:'GET',url:`${TG}/getFile?file_id=${fileId}`,json:true});
    const filePath=fileInfo?.result?.file_path;
    if(!filePath){await tgSend.call(this,chatId,'❌ Error al obtener el archivo.');clearSession();continue;}
    const fileUrl=`https://api.telegram.org/file/bot${BOT_TOKEN}/${filePath}`;
    const ocrPrompt='Analizá esta factura de proveedor. Extraé TODOS los productos/artículos. Devolvé SOLO un JSON array sin markdown ni texto extra: [{"tipo":"bicicleta","marca":"","modelo":"","descripcion":"","cantidad":1,"precio_unitario":"0","rodado":""}]. Tipos: bicicleta, cuadro, accesorio, otro. rodado: número para bicis/cuadros (ej 26, 29), vacío para accesorios.';
    let rawText='[]';
    try{
      const groqBody={model:'meta-llama/llama-4-scout-17b-16e-instruct',messages:[{role:'user',content:[{type:'image_url',image_url:{url:fileUrl}},{type:'text',text:ocrPrompt}]}],max_tokens:1000};
      const groqResp=await this.helpers.httpRequest({method:'POST',url:'https://api.groq.com/openai/v1/chat/completions',headers:{Authorization:`Bearer ${GROQ_KEY}`,'Content-Type':'application/json'},body:groqBody,json:true});
      rawText=groqResp.choices?.[0]?.message?.content||'[]';
    }catch(e){await tgSend.call(this,chatId,'❌ Error IA: '+e.message);clearSession();continue;}
    let productos=[];
    try{const s=rawText.indexOf('[');const e=rawText.lastIndexOf(']');if(s!==-1&&e!==-1)productos=JSON.parse(rawText.slice(s,e+1));}catch(e2){}
    if(!productos.length){await tgSend.call(this,chatId,'❌ No pude detectar productos. Intentá con una foto más nítida.');clearSession();continue;}
    let resumen=`📦 <b>Detecté ${productos.length} producto(s):</b>\n\n`;
    productos.forEach((p,i)=>{resumen+=`${i+1}. <b>${p.marca} ${p.modelo}</b> (${p.tipo})${p.rodado?' R'+p.rodado:''}\n   ${p.descripcion}\n   ${p.cantidad}u × $${p.precio_unitario}\n\n`;});
    resumen+='¿Dónde ingresan estos productos?';
    saveSession('FACT_PROV_UBIC',{productos});
    await tgSend.call(this,chatId,resumen,[[{text:'🏪 Local',callback_data:'fprov_local'},{text:'🏭 Galpón',callback_data:'fprov_galpon'}],[{text:'❌ Cancelar',callback_data:'main_menu'}]]);continue;
  }
  if(estado==='FACT_PROV_WAIT'&&text&&!cb){await tgSend.call(this,chatId,'📷 Necesito una foto o PDF de la factura. Por favor enviá el archivo.');continue;}
  if((cb==='fprov_local'||cb==='fprov_galpon')&&estado==='FACT_PROV_UBIC'){
    const ubicacion=cb==='fprov_local'?'local':'galpon';
    const{productos}=datos;
    saveSession('FACT_PROV_CONF',{productos,ubicacion});
    let conf=`✅ <b>Confirmar carga en ${ubicacion}:</b>\n\n`;
    productos.forEach((p,i)=>{conf+=`${i+1}. ${p.marca} ${p.modelo} × ${p.cantidad}\n`;});
    conf+='\n¿Guardamos en la hoja de Compras para revisión?';
    await tgSend.call(this,chatId,conf,[[{text:'✅ Guardar en Compras',callback_data:'fprov_ok'},{text:'❌ Cancelar',callback_data:'main_menu'}]]);continue;
  }
  if(cb==='fprov_ok'&&estado==='FACT_PROV_CONF'){
    const{productos,ubicacion}=datos;const t=now();
    for(const p of productos){
      gsWrites.push({_sheet:'COMPRAS',_op:'append',fecha:t,tipo:p.tipo,marca:p.marca||'',modelo:p.modelo||'',descripcion:p.descripcion||'',cantidad:String(p.cantidad||1),precio_unitario:p.precio_unitario||'0',rodado:p.rodado||'',ubicacion,estado:'pendiente'});
    }
    clearSession();
    await tgSend.call(this,chatId,`✅ <b>${productos.length} producto(s)</b> guardados en la hoja <b>COMPRAS</b>. Revisalos y pasalos al stock cuando quieras.`,[[{text:'🏠 Menú',callback_data:'main_menu'}]]);continue;
  }

  if(text&&!cb){await tgSend.call(this,chatId,'No entendí ese mensaje. Usá el menú 👇',mainMenu(rol));clearSession();}
}

if(!gsWrites.length)return [{json:{ok:true,processed:updates.length,writes:0}}];
return gsWrites.map(w=>({json:w}));
